-- ============================================================
-- BuilderTrend v2 Clients Import
-- Source: v2_jobsites_rollup.csv
-- ============================================================
-- Creates a `clients` row for each unique home_owner found in the BT
-- jobs file, with phone / email / address pulled from owner_* fields.
--
-- Idempotent: each insert is gated by NOT EXISTS on a case-insensitive
-- name match, so existing clients are never duplicated. Safe to re-run.
--
-- After running this, re-run the jobs.client_id backfill to link the
-- newly-inserted clients to their jobs.
-- ============================================================

BEGIN;

-- Stage candidates in a temp table to keep the INSERTs simple
CREATE TEMP TABLE _v2_client_candidates (
  name        TEXT,
  first_name  TEXT,
  last_name   TEXT,
  phone       TEXT,
  email       TEXT,
  street      TEXT,
  city        TEXT,
  state       TEXT,
  zip         TEXT
) ON COMMIT DROP;


-- Insert each candidate that doesn't already exist by name (case-insensitive)
SELECT v.name, v.first_name, v.last_name, v.phone, v.email, v.street, v.city, v.state, v.zip, 'individual'
FROM _v2_client_candidates v
WHERE NOT EXISTS (
  SELECT 1 FROM clients c
  WHERE LOWER(TRIM(c.name)) = LOWER(TRIM(v.name))
);

-- Now link jobs.client_id to the matching client by name
WITH job_unique AS (
  SELECT j.id AS job_id, sub.client_id
  FROM jobs j
  JOIN LATERAL (
    SELECT c.id AS client_id FROM clients c
    WHERE LOWER(TRIM(c.name)) = LOWER(TRIM(j.client_name))
    LIMIT 2
  ) sub ON TRUE
  WHERE j.client_id IS NULL
    AND TRIM(COALESCE(j.client_name,'')) <> ''
  GROUP BY j.id, sub.client_id
  HAVING COUNT(*) = 1
)
UPDATE jobs j SET client_id = u.client_id
FROM job_unique u WHERE j.id = u.job_id AND j.client_id IS NULL;

-- Final tally
SELECT
  (SELECT COUNT(*) FROM clients)                                AS total_clients,
  (SELECT COUNT(*) FROM jobs WHERE client_id IS NOT NULL)       AS jobs_with_client_id,
  (SELECT COUNT(*) FROM jobs WHERE client_id IS NULL)           AS jobs_without_client_id;

COMMIT;
